package com.fasterxml.jackson.dataformat.xml.ser;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "com.fasterxml.jackson.dataformat.xml.ser.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package com.fasterxml.jackson.dataformat.xml.ser.steps;

import com.fasterxml.jackson.annotation.JsonProperty;
import com.fasterxml.jackson.databind.annotation.JsonSerialize;
import com.fasterxml.jackson.dataformat.xml.XmlMapper;
import com.fasterxml.jackson.dataformat.xml.annotation.JacksonXmlRootElement;
import io.cucumber.java.en.*;
import static org.junit.Assert.*;

public class StepDefs {

    private XmlMapper mapper1;
    private XmlMapper mapper2;
    private String output1;
    private String output2;

    @JacksonXmlRootElement(localName = "AnnotatedName")
    public static class Pojo282 {
        @JsonProperty
        public String value = "test";
    }

    @Given("a POJO class {string} annotated with @JacksonXmlRootElement(localName = {string})")
    public void a_pojo_class_annotated_with_jackson_xml_root_element(String className, String localName) {
        // Class is defined above
    }

    @Given("an XmlMapper {string} is created with default settings")
    public void an_xml_mapper_is_created_with_default_settings(String mapperName) {
        if ("mapper1".equals(mapperName)) {
            mapper1 = new XmlMapper();
        } else if ("mapper2".equals(mapperName)) {
            mapper2 = new XmlMapper();
        }
    }

    @Given("{string} is configured to use annotations")
    public void mapper_is_configured_to_use_annotations(String mapperName) {
        if ("mapper1".equals(mapperName)) {
            mapper1 = mapper1.copy();
            mapper1.enable(com.fasterxml.jackson.databind.MapperFeature.USE_ANNOTATIONS);
        }
    }

    @Given("a copy of {string} named {string} is created")
    public void a_copy_of_mapper_named_mapper_is_created(String originalMapper, String copyMapper) {
        if ("mapper1".equals(originalMapper) && "mapper2".equals(copyMapper)) {
            mapper2 = mapper1.copy();
        }
    }

    @Given("{string} is configured to disable USE_ANNOTATIONS")
    public void mapper_is_configured_to_disable_use_annotations(String mapperName) {
        if ("mapper2".equals(mapperName)) {
            mapper2 = mapper2.copy();
            mapper2.disable(com.fasterxml.jackson.databind.MapperFeature.USE_ANNOTATIONS);
        }
    }

    @Given("{string} is configured to disable FAIL_ON_EMPTY_BEANS")
    public void mapper_is_configured_to_disable_fail_on_empty_beans(String mapperName) {
        if ("mapper2".equals(mapperName)) {
            mapper2 = mapper2.copy();
            mapper2.disable(com.fasterxml.jackson.databind.SerializationFeature.FAIL_ON_EMPTY_BEANS);
        }
    }

    @When("{string} serializes an instance of {string}")
    public void mapper_serializes_an_instance_of(String mapperName, String className) {
        try {
            if ("mapper1".equals(mapperName) && "Pojo282".equals(className)) {
                output1 = mapper1.writeValueAsString(new Pojo282());
            } else if ("mapper2".equals(mapperName) && "Pojo282".equals(className)) {
                output2 = mapper2.writeValueAsString(new Pojo282());
            }
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    @Then("the output from {string} should contain {string}")
    public void the_output_from_mapper_should_contain(String mapperName, String content) {
        if ("mapper1".equals(mapperName)) {
            assertTrue("Output from mapper1 should contain " + content + ", but was: " + output1, 
                      output1.contains(content));
        } else if ("mapper2".equals(mapperName)) {
            assertTrue("Output from mapper2 should contain " + content + ", but was: " + output2, 
                      output2.contains(content));
        }
    }

    @Then("the output from {string} should NOT contain {string}")
    public void the_output_from_mapper_should_not_contain(String mapperName, String content) {
        if ("mapper2".equals(mapperName)) {
            assertFalse("Output from mapper2 should NOT contain " + content + ", but was: " + output2, 
                       output2.contains(content));
        }
    }
}
